#include <stdio.h>

void deleteElement(int arr[], int *n, int position) {
    if (*n == 0) {
        printf("Array is empty!\n");
        return;
    }
    if (position < 0 || position >= *n) {
        printf("Invalid position!\n");
        return;
    }

    // Shift elements to the left
    for (int i = position; i < *n - 1; i++) {
        arr[i] = arr[i + 1];
    }

    (*n)--;
}

int main() {
    int arr[10] = {10, 20, 30, 40, 50};
    int n = 5;

    deleteElement(arr, &n, 2);

    for (int i = 0; i < n; i++)
        printf("%d ", arr[i]);
    // Output: 10 20 40 50
    return 0;
}

public class ArrayAddress {
    public static int calculateAddress(int baseAddr, int row, int col, 
                                       int numCols, int elementSize) {
        // Row-major: Address = Base + ((row * numCols) + col) * size
        int offset = (row * numCols + col) * elementSize;
        return baseAddr + offset;
    }

    public static void main(String[] args) {
        int baseAddress = 1000;
        int elementSize = 4; // 4 bytes for int
        int[][] arr = new int[4][5]; // 4 rows, 5 columns

        // Find address of arr[2][3]
        int address = calculateAddress(baseAddress, 2, 3, 5, elementSize);
        System.out.println("Address: " + address); // Output: 1044
    }
}
